mapper.select:
SELECT

FROM t_dy_comm a

WHERE a.id = #{id}

SELECT

FROM t_dy_comm a


	a.del_flag = #{DEL_FLAG_NORMAL}
	${dataScope}

		AND a.uid = #{u.id}


		AND (u.idno = #{idno} OR u.lianghao = #{idno})


		AND (u.idno = #{u.idno} OR u.lianghao = #{u.idno})


		AND u.lianghao LIKE concat('%', #{u.lianghao}, '%')


		AND a.dy_id = #{dy.id}


		AND a.level = #{level}




		ORDER BY ${page.orderBy}


		ORDER BY a.create_date DESC

SELECT

FROM t_dy_comm a


	a.del_flag = #{DEL_FLAG_NORMAL}
	${dataScope}

		AND a.uid = #{u.id}


		AND (u.idno = #{idno} OR u.lianghao = #{idno})


		AND (u.idno = #{u.idno} OR u.lianghao = #{u.idno})


		AND u.lianghao LIKE concat('%', #{u.lianghao}, '%')


		AND a.dy_id = #{dy.id}


		AND a.level = #{level}




		ORDER BY ${page.orderBy}


		ORDER BY a.update_date DESC

mapper.update:
